        exit(1);
    }
}

__global__ void nw_top_left_kernel(int *input_itemsets, const int *referrence,
                                   int max_rows, int max_cols, int penalty, int blk)
{
    if (threadIdx.x != 0 || blockIdx.x >= (unsigned int)blk)
        return;

    const int elem_19 = (int)blockIdx.x;
    const int item_11 = blk - 1 - elem_19;

    int elem_23[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int item_16[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            item_16[i * BLOCK_SIZE + j] =
                referrence[max_cols * (item_11 * BLOCK_SIZE + i + 1) + elem_19 * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            elem_23[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (item_11 * BLOCK_SIZE + i) + elem_19 * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            elem_23[i * (BLOCK_SIZE + 1) + j] =
                maximum(elem_23[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + item_16[(i - 1) * BLOCK_SIZE + j - 1],
                        elem_23[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                        elem_23[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (item_11 * BLOCK_SIZE + i + 1) + elem_19 * BLOCK_SIZE + j + 1] =
                elem_23[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void nw_bottom_right_kernel(int *input_itemsets, const int *referrence,
                                       int max_rows, int max_cols, int penalty, int blk, int num_tiles)
{
    if (threadIdx.x != 0)
        return;

    const int local_idx = (int)blockIdx.x;
    const int elem_10 = blk - 1 + local_idx;
    if (elem_10 >= num_tiles)
        return;

    const int elem_2 = num_tiles + blk - 2 - elem_10;

    int var_1[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int tmp_12[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            tmp_12[i * BLOCK_SIZE + j] =
                referrence[max_cols * (elem_2 * BLOCK_SIZE + i + 1) + elem_10 * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            var_1[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (elem_2 * BLOCK_SIZE + i) + elem_10 * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            var_1[i * (BLOCK_SIZE + 1) + j] =
                maximum(var_1[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + tmp_12[(i - 1) * BLOCK_SIZE + j - 1],
                        var_1[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                        var_1[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (elem_2 * BLOCK_SIZE + i + 1) + elem_10 * BLOCK_SIZE + j + 1] =
                var_1[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *tmp_0, int *referrence,
                  int max_rows, int max_cols, int penalty)
{
    (void)tmp_0;

    const size_t transfer_size = (size_t)max_rows * (size_t)max_cols;
    const size_t bytes = transfer_size * sizeof(int);

    int *d_input_itemsets = NULL;
    int *d_referrence = NULL;

    cuda_check(cudaMalloc((void **)&d_input_itemsets, bytes));
    cuda_check(cudaMalloc((void **)&d_referrence, bytes));

    cuda_check(cudaMemcpy(d_input_itemsets, input_itemsets, bytes, cudaMemcpyHostToDevice));
    cuda_check(cudaMemcpy(d_referrence, referrence, bytes, cudaMemcpyHostToDevice));

    const int num_tiles = (max_cols - 1) / BLOCK_SIZE;

    for (int blk = 1; blk <= num_tiles; blk++) {
        nw_top_left_kernel<<<blk, 1>>>(d_input_itemsets, d_referrence, max_rows, max_cols, penalty, blk);
        cuda_check(cudaGetLastError());
    }

    cuda_check(cudaDeviceSynchronize());

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= num_tiles; blk++) {
        const int grid = num_tiles - blk + 1;
        nw_bottom_right_kernel<<<grid, 1>>>(d_input_itemsets, d_referrence, max_rows, max_cols, penalty, blk, num_tiles);
        cuda_check(cudaGetLastError());
    }

    cuda_check(cudaMemcpy(input_itemsets, d_input_itemsets, bytes, cudaMemcpyDeviceToHost));

    cuda_check(cudaFree(d_input_itemsets));
    cuda_check(cudaFree(d_referrence));
}

